import type { TokenData } from 'llama.rn'

import { STREAMING } from '../lib/constants'
import { sanitiseModelResponse } from '../lib/chat/response-sanitizer'
import { storeApi } from '../store'

export type TokenStreamActivity = 'content' | 'thinking' | 'none'

type StreamState = {
  readonly messageId: string
  contentBuffer: string
  thinkingBuffer: string
  frameHandle: number | null
  rawContent: string
  rawThinking: string
  emittedContent: string
  emittedThinking: string
}

const streams = new Map<string, StreamState>()

const scheduleFrame = (callback: () => void): number => {
  if (typeof requestAnimationFrame === 'function') {
    return requestAnimationFrame(() => callback())
  }
  return setTimeout(callback, 16) as unknown as number
}

const cancelFrame = (handle: number): void => {
  if (typeof cancelAnimationFrame === 'function') {
    cancelAnimationFrame(handle)
    return
  }
  clearTimeout(handle)
}

const streamState = (messageId: string): StreamState => {
  const existing = streams.get(messageId)
  if (existing !== undefined) return existing

  const next: StreamState = {
    messageId,
    contentBuffer: '',
    thinkingBuffer: '',
    frameHandle: null,
    rawContent: '',
    rawThinking: '',
    emittedContent: '',
    emittedThinking: '',
  }
  streams.set(messageId, next)
  return next
}

const hasBufferedStream = (state: StreamState): boolean =>
  state.contentBuffer !== '' || state.thinkingBuffer !== ''

const flushStreamChunk = (state: StreamState): void => {
  if (state.thinkingBuffer !== '') {
    const chunk = state.thinkingBuffer.slice(0, STREAMING.MAX_CHUNK_PER_FLUSH)
    state.thinkingBuffer = state.thinkingBuffer.slice(chunk.length)
    storeApi.get().appendThinkingChunk(state.messageId, chunk)
  }

  if (state.contentBuffer !== '') {
    const chunk = state.contentBuffer.slice(0, STREAMING.MAX_CHUNK_PER_FLUSH)
    state.contentBuffer = state.contentBuffer.slice(chunk.length)
    storeApi.get().appendStreamingChunk(state.messageId, chunk)
  }
}

const flushStream = (messageId: string): void => {
  const state = streams.get(messageId)
  if (state === undefined) return

  state.frameHandle = null
  if (!hasBufferedStream(state)) return

  flushStreamChunk(state)

  if (hasBufferedStream(state)) {
    state.frameHandle = scheduleFrame(() => flushStream(messageId))
  }
}

export const appendBuffered = (messageId: string, chunk: string): void => {
  if (chunk === '') return
  const state = streamState(messageId)
  state.contentBuffer += chunk
  if (state.frameHandle === null) {
    state.frameHandle = scheduleFrame(() => flushStream(messageId))
  }
}

const appendThinkingBuffered = (messageId: string, chunk: string): void => {
  if (chunk === '') return
  const state = streamState(messageId)
  state.thinkingBuffer += chunk
  if (state.frameHandle === null) {
    state.frameHandle = scheduleFrame(() => flushStream(messageId))
  }
}

export const finishStream = (messageId: string): void => {
  const state = streams.get(messageId)
  if (state === undefined) return
  if (state.frameHandle !== null) cancelFrame(state.frameHandle)
  state.frameHandle = null
  while (hasBufferedStream(state)) {
    flushStreamChunk(state)
  }
  storeApi.get().markThinkingDone(messageId)
  streams.delete(messageId)
}

const appendCumulativeDelta = (
  previous: string,
  next: string | undefined,
  append: (chunk: string) => void,
): { emitted: string; changed: boolean } => {
  if (next === undefined || next === previous) {
    return { emitted: previous, changed: false }
  }

  if (!next.startsWith(previous)) {
    return { emitted: next, changed: false }
  }

  const delta = next.slice(previous.length)
  append(delta)
  return { emitted: next, changed: delta !== '' }
}

export const appendTokenData = (messageId: string, token: TokenData): TokenStreamActivity => {
  const state = streamState(messageId)

  if (typeof token.content === 'string') state.rawContent = token.content
  if (typeof token.reasoning_content === 'string') state.rawThinking = token.reasoning_content

  const sanitised = sanitiseModelResponse(state.rawContent, state.rawThinking)
  const thinkingEnabled = storeApi.get().thinkingEnabled

  const content = appendCumulativeDelta(state.emittedContent, sanitised.content, (chunk) => {
    appendBuffered(messageId, chunk)
  })
  state.emittedContent = content.emitted

  const thinking = appendCumulativeDelta(state.emittedThinking, thinkingEnabled ? sanitised.thinking : '', (chunk) => {
    appendThinkingBuffered(messageId, chunk)
  })
  state.emittedThinking = thinking.emitted

  if (content.changed || state.emittedContent !== '') return 'content'
  if (thinking.changed) return 'thinking'
  return 'none'
}

import type { Message as SdkMessage } from '@jeffs-brain/memory-react-native'
import type { RNLlamaMessagePart, RNLlamaOAICompatibleMessage } from 'llama.rn'

import { SYSTEM_PROMPT } from '../lib/constants'
import type { ContentPart, Message } from '../store/types'

const MEDIA_MARKER = '<__media__>'

export type MediaPrompt = {
  readonly prompt: string
  readonly mediaPaths: readonly string[]
}

const visibleTextFromParts = (parts: readonly ContentPart[]): string =>
  parts
    .filter((part): part is Extract<ContentPart, { type: 'text' }> => part.type === 'text')
    .map((part) => part.text)
    .join('\n')

const fileContextFromPart = (part: Extract<ContentPart, { type: 'file' }>): string => {
  const metadata = [
    `Attached file: ${part.name}`,
    part.mimeType === undefined ? null : `MIME type: ${part.mimeType}`,
    part.size === undefined ? null : `Size: ${part.size} bytes`,
  ].filter((line): line is string => line !== null)

  return `${metadata.join('\n')}\n\n${part.text}`
}

export const textFromParts = (parts: readonly ContentPart[]): string =>
  parts
    .filter((part): part is Extract<ContentPart, { type: 'text' | 'file' }> =>
      part.type === 'text' || part.type === 'file',
    )
    .map((part) => part.type === 'text' ? part.text : fileContextFromPart(part))
    .join('\n\n')

const mediaPlaceholder = (parts: readonly ContentPart[]): string | null => {
  const hasImage = parts.some((part) => part.type === 'image')
  const hasAudio = parts.some((part) => part.type === 'audio')
  if (!hasImage && !hasAudio) return null
  if (hasImage && hasAudio) return '[Previous image and audio attachments omitted from this turn.]'
  if (hasImage) return '[Previous image attachment omitted from this turn.]'
  return '[Previous audio attachment omitted from this turn.]'
}

const cloudMediaPlaceholder = (parts: readonly ContentPart[]): string | null => {
  const hasImage = parts.some((part) => part.type === 'image')
  const hasAudio = parts.some((part) => part.type === 'audio')
  if (!hasImage && !hasAudio) return null
  if (hasImage && hasAudio) return '[Image and audio attachments were not sent to the cloud provider.]'
  if (hasImage) return '[Image attachment was not sent to the cloud provider.]'
  return '[Audio attachment was not sent to the cloud provider.]'
}

const toLlamaContent = (
  parts: readonly ContentPart[],
  includeMedia: boolean,
): string | RNLlamaMessagePart[] => {
  if (!includeMedia) {
    return [textFromParts(parts).trim(), mediaPlaceholder(parts)]
      .filter((part): part is string => part !== null && part !== '')
      .join('\n\n')
  }

  const mediaParts = parts
    .filter((part): part is Extract<ContentPart, { type: 'image' | 'audio' }> =>
      part.type === 'image' || part.type === 'audio',
    )
    .map((part): RNLlamaMessagePart =>
      part.type === 'image'
        ? { type: 'image_url', image_url: { url: part.uri } }
        : { type: 'input_audio', input_audio: { url: part.uri, format: 'wav' } },
    )

  if (mediaParts.length === 0) return textFromParts(parts)

  const text = textFromParts(parts)
  return [
    ...(text.trim() === '' ? [] : [{ type: 'text' as const, text }]),
    ...mediaParts,
  ]
}

const toLlamaMessage = (
  message: Message,
  includeMediaForMessage: boolean,
): RNLlamaOAICompatibleMessage | null => {
  if (message.role === 'tool') return null
  return {
    role: message.role,
    content: toLlamaContent(message.parts, includeMediaForMessage),
  }
}

const isMediaPart = (part: ContentPart): part is Extract<ContentPart, { type: 'image' | 'audio' }> =>
  part.type === 'image' || part.type === 'audio'

export const messageRequiresMultimodal = (message: Message): boolean => message.parts.some(isMediaPart)

const nativeMediaPath = (part: Extract<ContentPart, { type: 'image' | 'audio' }>): string =>
  part.uri.startsWith('file://') ? part.uri.slice(7) : part.uri

export const latestUserRequiresMultimodal = (messages: readonly Message[]): boolean => {
  for (let index = messages.length - 1; index >= 0; index -= 1) {
    const message = messages[index]
    if (message?.role === 'user') return messageRequiresMultimodal(message)
  }
  return false
}

const latestUserMediaMessageId = (messages: readonly Message[]): string | null => {
  for (let index = messages.length - 1; index >= 0; index -= 1) {
    const message = messages[index]
    if (message?.role !== 'user') continue
    return messageRequiresMultimodal(message) ? message.id : null
  }
  return null
}

export const latestUserText = (messages: readonly Message[]): string => {
  for (let index = messages.length - 1; index >= 0; index -= 1) {
    const message = messages[index]
    if (message?.role === 'user') return visibleTextFromParts(message.parts)
  }
  return ''
}

export const latestUserMediaPrompt = (messages: readonly Message[]): MediaPrompt | null => {
  for (let index = messages.length - 1; index >= 0; index -= 1) {
    const message = messages[index]
    if (message?.role !== 'user') continue

    const mediaParts = message.parts.filter(isMediaPart)
    if (mediaParts.length === 0) return null

    const text = textFromParts(message.parts).trim() || 'Describe the attached media.'
    return {
      prompt: [
        SYSTEM_PROMPT,
        'Current user message:',
        text,
        mediaParts.map(() => MEDIA_MARKER).join('\n'),
        'Answer the current user message using the attached media.',
      ].join('\n\n'),
      mediaPaths: mediaParts.map(nativeMediaPath),
    }
  }

  return null
}

export const buildLlamaMessages = (
  messages: readonly Message[],
  activeAssistantId: string,
  includeMedia: boolean,
): RNLlamaOAICompatibleMessage[] => {
  const mediaMessageId = includeMedia ? latestUserMediaMessageId(messages) : null
  const historical = messages
    .filter((message) => message.id !== activeAssistantId)
    .map((message) => toLlamaMessage(message, message.id === mediaMessageId))
    .filter((message): message is RNLlamaOAICompatibleMessage => message !== null)

  return [{ role: 'system', content: SYSTEM_PROMPT }, ...historical]
}

const toCloudMessage = (message: Message): SdkMessage | null => {
  if (message.role === 'tool') return null
  const text = textFromParts(message.parts).trim()
  const placeholder = cloudMediaPlaceholder(message.parts)
  const content = [text, placeholder]
    .filter((part): part is string => part !== null && part !== '')
    .join('\n\n')
  if (content === '') return null
  return { role: message.role, content }
}

export const buildCloudMessages = (
  messages: readonly Message[],
  activeAssistantId: string,
): SdkMessage[] =>
  messages
    .filter((message) => message.id !== activeAssistantId)
    .map(toCloudMessage)
    .filter((message): message is SdkMessage => message !== null)

