import type { MemoryNoteSummary, ToolLogEntry } from '../store/slices/memory'

export const formatMemoryDate = (value: string): string => {
  const date = new Date(value)
  if (Number.isNaN(date.getTime())) return value
  return date.toLocaleString([], {
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    month: 'short',
    year: 'numeric',
  })
}

export const formatRelativeDate = (value: string): string => {
  const date = new Date(value)
  if (Number.isNaN(date.getTime())) return ''
  const now = Date.now()
  const diffMs = now - date.getTime()
  const diffSeconds = Math.floor(diffMs / 1000)
  const diffMinutes = Math.floor(diffSeconds / 60)
  const diffHours = Math.floor(diffMinutes / 60)
  const diffDays = Math.floor(diffHours / 24)

  if (diffSeconds < 60) return 'just now'
  if (diffMinutes < 60) return `${diffMinutes}m ago`
  if (diffHours < 24) return `${diffHours}h ago`
  if (diffDays < 7) return `${diffDays}d ago`
  if (diffDays < 30) return `${Math.floor(diffDays / 7)}w ago`
  return `${Math.floor(diffDays / 30)}mo ago`
}

export const formatLogTime = (value: number): string =>
  new Date(value).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })

export const memoryStatusCopy = (status: string, count: number): string => {
  if (status === 'loading') return count === 0 ? 'Loading memories' : 'Refreshing memories'
  if (count === 0) return 'No durable memories stored yet'
  return `${count} stored memor${count === 1 ? 'y' : 'ies'}`
}

export const cleanMemoryText = (value: string | undefined): string => value?.trim() ?? ''

const isOpenLogEntry = (entry: ToolLogEntry): boolean =>
  entry.status === 'pending' || entry.status === 'running'

export const recentVisibleMemoryLog = (entries: readonly ToolLogEntry[]): ToolLogEntry[] => {
  const recent = entries.slice(-24)
  const visible = recent.filter((entry, index) => {
    if (!isOpenLogEntry(entry)) return true
    return !recent
      .slice(index + 1)
      .some((candidate) => candidate.tool === entry.tool && !isOpenLogEntry(candidate))
  })
  const seen = new Set<string>()
  const unique: ToolLogEntry[] = []

  for (const entry of visible.slice().reverse()) {
    const key = `${entry.tool}:${entry.status}:${entry.detail ?? ''}`
    if (seen.has(key)) continue
    seen.add(key)
    unique.push(entry)
    if (unique.length === 8) break
  }

  return unique
}

export const filterMemoryNotes = (
  notes: readonly MemoryNoteSummary[],
  rawQuery: string,
): readonly MemoryNoteSummary[] => {
  const query = rawQuery.trim().toLowerCase()
  if (query === '') return notes
  return notes.filter((note) =>
    note.name.toLowerCase().includes(query) ||
    note.preview?.toLowerCase().includes(query) ||
    note.description?.toLowerCase().includes(query) ||
    note.tags.join(' ').toLowerCase().includes(query),
  )
}

import { useCallback, useEffect, useMemo, useState } from 'react'
import * as DocumentPicker from 'expo-document-picker'
import { useRouter } from 'expo-router'
import { Alert, ScrollView, StyleSheet, Text, TextInput, View } from 'react-native'
import { useSafeAreaInsets } from 'react-native-safe-area-context'

import { DoneButton, HeaderButton } from '../components/memory/MemoryButtons'
import { MemoryNoteCard } from '../components/memory/MemoryNoteCard'
import { ToolLogRow } from '../components/memory/ToolLogRow'
import {
  filterMemoryNotes,
  memoryStatusCopy,
  recentVisibleMemoryLog,
} from '../lib/memory-display'
import { colors, radius, shadows } from '../lib/theme'
import { memoryService } from '../services/memory'
import { useStore } from '../store'
import type { MemoryNoteSummary } from '../store/slices/memory'

export default function Memories() {
  const insets = useSafeAreaInsets()
  const router = useRouter()
  const [expandedPath, setExpandedPath] = useState<string | null>(null)
  const [deletingPath, setDeletingPath] = useState<string | null>(null)
  const [importing, setImporting] = useState(false)
  const [searchQuery, setSearchQuery] = useState('')
  const memoryNotes = useStore((s) => s.memoryNotes)
  const memoryNotesStatus = useStore((s) => s.memoryNotesStatus)
  const memoryNotesError = useStore((s) => s.memoryNotesError)
  const lastExtractionSummary = useStore((s) => s.lastExtractionSummary)
  const memoryActivityLog = useStore((s) => s.memoryActivityLog)
  const recentMemoryLog = useMemo(() => recentVisibleMemoryLog(memoryActivityLog), [memoryActivityLog])
  const filteredNotes = useMemo(
    () => filterMemoryNotes(memoryNotes, searchQuery),
    [memoryNotes, searchQuery],
  )
  const loading = memoryNotesStatus === 'loading'

  useEffect(() => {
    void memoryService.listMemories()
  }, [])

  const handleRefresh = useCallback(() => {
    void memoryService.listMemories()
  }, [])

  const handleTidy = useCallback(() => {
    void memoryService.consolidateMemories()
  }, [])

  const handleImport = useCallback(() => {
    if (importing || loading) return

    setImporting(true)
    void (async () => {
      const result = await DocumentPicker.getDocumentAsync({
        copyToCacheDirectory: true,
        multiple: false,
        type: [
          'application/pdf',
          'text/*',
          'text/markdown',
          'application/json',
          'application/xml',
          'application/yaml',
          'application/x-yaml',
        ],
      })
      if (result.canceled) return

      const asset = result.assets[0]
      if (asset === undefined) return

      const imported = await memoryService.importDocument({
        uri: asset.uri,
        name: asset.name,
        ...(asset.mimeType === undefined ? {} : { mimeType: asset.mimeType }),
        ...(asset.size === undefined ? {} : { size: asset.size }),
      })
      if (imported === null) return
      Alert.alert(
        'Imported document',
        `${imported.title}\n\n${imported.noteCount} searchable chunk${imported.noteCount === 1 ? '' : 's'} added to Jeff's brain.`,
      )
    })().finally(() => setImporting(false))
  }, [importing, loading])

  const handleToggle = useCallback((path: string) => {
