      const llamaChatResult = formattedResult as FormattedChatResult
      nativeParams.prompt = llamaChatResult.prompt || ''
      if (llamaChatResult.has_media) {
        nativeParams.media_paths = llamaChatResult.media_paths
      }
    }
  } else {
